  assert.match(webgpu, /GPUTextureUsage\.RENDER_ATTACHMENT \| GPUTextureUsage\.TEXTURE_BINDING \| GPUTextureUsage\.COPY_DST/);
  assert.match(webgpu, /createWaterCausticsBindGroup/);
