// Regression test for the "hidden-at-hydration" CanvasBoard defect: a
// <canvas> with no CSS width/height override renders at its OWN width/height
// CONTENT ATTRIBUTES — the very attributes _initEngineSurfaceCanvasSize
// writes. Once mounted while its box is collapsed (host CSS never gives the
// canvas OR a close ancestor a real box — whether it hydrated behind a
// display:none workbench panel, or a host CSS selector no longer matches
// after an upstream DOM-nesting change), a bare getBoundingClientRect()
// measurement is a stable 1x1 fixed point: ResizeObserver still fires
// correctly on every subsequent layout change, but it keeps re-measuring the
// same self-referential 1x1 box forever. _measuredCanvasCSSBox must walk up
// to the first real-boxed ancestor instead, capped at the board's declared
// size, and keep observing that ancestor for later layout changes.
test("canvas2d surface recovers from a self-referential 1x1 backing store by sizing from the nearest real-boxed ancestor", async () => {
  const env = createContext({});
  installManualRAF(env.context);

  // Mirrors the real regression: the immediate parent (.studio-site-map-canvas)
  // is ALSO still collapsed (a broken host CSS selector never gave it a real
  // height either), but the grandparent (.studio-advanced-canvas-board) has a
  // real box — the fix must walk past the degenerate parent to find it.
  const grandparent = new FakeElement("section", env.context.document);
  grandparent.clientWidth = 746;
  grandparent.clientHeight = 738;

  const parent = new FakeElement("section", env.context.document);
  parent.clientWidth = 746;
  parent.clientHeight = 20;
  grandparent.appendChild(parent);
  parent.parentElement = grandparent;

  const canvas = new FakeElement("canvas", env.context.document);
  canvas.setAttribute("data-gosx-surface-kind", "canvas2d");
  canvas.setAttribute("width", "1280");
  canvas.setAttribute("height", "720");
  canvas.width = 1280;
  canvas.height = 720;
  canvas.isConnected = true;
  canvas.focus = () => {};
  // The canvas's own box is stuck at 1x1 — the self-referential collapse this
  // fix must recover from (unaffected by anything this test does to the
  // ancestors above).
  canvas.getBoundingClientRect = () => ({ width: 1, height: 1, left: 0, top: 0 });
  parent.appendChild(canvas);
  canvas.parentElement = parent;
  env.context.document.body.appendChild(grandparent);

  env.context.document.querySelectorAll = function(selector) {
    if (selector === "[data-gosx-surface-kind]:not([data-gosx-engine-bytecode])") {
      return canvas.hasAttribute("data-gosx-engine-bytecode") ? [] : [canvas];
    }
    return [];
  };

  runScript(bootstrapRuntimeSource, env.context, "bootstrap-runtime.js");
  runScript(bootstrapFeatureEnginesSource, env.context, "bootstrap-feature-engines.js");
  const enginesFactory = env.context.__gosx_bootstrap_features && env.context.__gosx_bootstrap_features.engines;
  assert.equal(typeof enginesFactory, "function", "engines feature factory must be registered");

  env.context.__gosx_hydrate = function() { return ""; };

  const feature = enginesFactory({
    engineFactories: {},
    sceneNumber: (v, d) => (typeof v === "number" ? v : d),
    sceneBool: (v, d) => (typeof v === "boolean" ? v : d),
  });

  await feature.runtimeReady({});
  await flushAsyncWork();

  // Mount alone must already recover — the walk runs unconditionally, not
  // just on a later ResizeObserver fire — picking the largest-area real
  // ancestor within reach, capped at the board's declared 1280x720.
  assert.equal(canvas.width, 746, "backing store width must recover from the grandparent's real box");
  assert.equal(canvas.height, 720, "backing store height must be capped at the board's declared height");

  // The fallback must also register the discovered ancestor with the SAME
  // ResizeObserver, so a LATER layout change there (the canvas's own box never
  // changes on its own) re-triggers the recovery. Real browsers deliver a
  // ResizeObserver's first notification shortly after observe() is called
  // (proven empirically against real Chromium — see the handoff report); the
  // fake observer here requires an explicit trigger to model that first fire.
  const ro = env.resizeObservers[0];
  assert.ok(ro, "a ResizeObserver must have been created for the canvas2d board");
  assert.ok(ro.targets.has(canvas), "the observer must still observe the canvas itself");
  ro.trigger([canvas]);
  assert.ok(ro.targets.has(grandparent), "the observer must ALSO observe the ancestor it fell back to");

  // Simulate the ancestor's box changing later (e.g. a rail collapse widens
  // the workbench) — re-triggering the observer picks up the new size even
  // though the canvas's own (still self-referential) box never moved.
  grandparent.clientWidth = 900;
  grandparent.clientHeight = 700;
  ro.trigger([canvas]);
  assert.equal(canvas.width, 900);
  assert.equal(canvas.height, 700);
});

// -----------------------------------------------------------------------------
// Canvas2D painter — paintCanvasBundle(ctx, bundle, cssWidth, cssHeight, dpr)
//
// The painter is the JS half of the canvas2d paint loop: it takes a
// RenderBundle (as emitted by __gosx_render_canvas), computes the screen
// transform from the OrthoCamera2D contract (mode "ortho2d"; camera.x = panX,
// camera.y = panY, camera.z = zoom), and replays the bundle's objects/lines/
// labels onto a 2D context. The transform it must replicate is:
//
//     screenX = (worldX - panX) * zoom + cssWidth / 2
//     screenY = (cssHeight / 2) - (worldY - panY) * zoom   (NDC +Y up → canvas +Y down)
//
// These tests feed a hand-built bundle to a FAKE 2D context that records every
// draw call and assert the resulting screen coordinates.
// -----------------------------------------------------------------------------

// loadCanvasPainter evaluates the standalone painter fragment in an isolated
// sandbox and returns the exposed window.__gosx_paint_canvas_bundle function.
function loadCanvasPainter() {
  const source = fs.readFileSync(
    path.join(__dirname, "bootstrap-src", "26b1-canvas2d-painter.js"),
    "utf8",
  );
  const sandbox = {};
  sandbox.window = sandbox;
  vm.createContext(sandbox);
  vm.runInContext(source, sandbox, { filename: "26b1-canvas2d-painter.js" });
  const fn = sandbox.window.__gosx_paint_canvas_bundle;
  assert.equal(typeof fn, "function", "painter must expose window.__gosx_paint_canvas_bundle");
  return fn;
}

// makeFakeContext2D returns a CanvasRenderingContext2D-like recorder. It tracks
// fillStyle/strokeStyle/lineWidth/font assignments and records each draw call
// (with the style in effect at call time) into a flat `calls` array.
function makeFakeContext2D() {
  const ctx = {
    fillStyle: "",
    strokeStyle: "",
    lineWidth: 1,
    font: "",
    textBaseline: "",
    textAlign: "",
    calls: [],
  };
  ctx.clearRect = (x, y, w, h) => ctx.calls.push({ op: "clearRect", x, y, w, h });
  ctx.fillRect = (x, y, w, h) =>
    ctx.calls.push({ op: "fillRect", x, y, w, h, fillStyle: ctx.fillStyle });
  ctx.beginPath = () => ctx.calls.push({ op: "beginPath" });
  ctx.moveTo = (x, y) => ctx.calls.push({ op: "moveTo", x, y });
  ctx.lineTo = (x, y) => ctx.calls.push({ op: "lineTo", x, y });
  ctx.stroke = () =>
    ctx.calls.push({ op: "stroke", strokeStyle: ctx.strokeStyle, lineWidth: ctx.lineWidth });
  ctx.fillText = (text, x, y) =>
    ctx.calls.push({ op: "fillText", text, x, y, fillStyle: ctx.fillStyle, font: ctx.font });
  ctx.save = () => ctx.calls.push({ op: "save" });
  ctx.restore = () => ctx.calls.push({ op: "restore" });
  ctx.setTransform = (a, b, c, d, e, f) =>
    ctx.calls.push({ op: "setTransform", a, b, c, d, e, f });
  ctx.scale = (x, y) => ctx.calls.push({ op: "scale", x, y });
  return ctx;
}

function callsOfType(ctx, op) {
  return ctx.calls.filter((c) => c.op === op);
}

// nodeFillRects returns fillRect calls that are NOT the full-viewport background
// fill (which the painter emits at the origin in CSS-logical pixels; the caller
// pre-scales the context for the device pixel ratio, so dpr does not change the
// logical fill region).
function nodeFillRects(ctx, cssWidth, cssHeight) {
  return callsOfType(ctx, "fillRect").filter(
    (c) => !(c.x === 0 && c.y === 0 && c.w === cssWidth && c.h === cssHeight),
  );
}

test("paintCanvasBundle clears with the bundle background then paints a rect at the OrthoCamera2D origin (zoom 1, pan 0)", () => {
  const paint = loadCanvasPainter();
  const ctx = makeFakeContext2D();

  const bundle = {
    background: "#0f1720",
    camera: { mode: "ortho2d", x: 0, y: 0, z: 1 },
    materials: [{ color: "#ff8866" }],
    objects: [
      {
        kind: "rect",
        materialIndex: 0,
        bounds: { minX: -22, maxX: 22, minY: -16, maxY: 16 },
      },
    ],
    lines: [],
    labels: [],
  };

  paint(ctx, bundle, 800, 600, 1);

  // Background clear/fill happens.
  const clears = callsOfType(ctx, "clearRect");
  const fills = nodeFillRects(ctx, 800, 600);
  assert.ok(clears.length >= 1, "expected a clearRect for the frame");
  assert.equal(fills.length, 1, "expected exactly one node fillRect for the rect node");

  // World rect (-22..22, -16..16) at zoom 1, pan 0, viewport 800x600 maps to
  // screen x in [378, 422] and (Y flipped) screen y in [284, 316].
  // top-left screen corner = (minX→378, maxY→284); width=44, height=32.
  const rect = fills[0];
  assert.equal(rect.fillStyle, "#ff8866", "rect must use its material color");
  assert.ok(Math.abs(rect.x - 378) < 1e-6, `rect x = ${rect.x}, want 378`);
  assert.ok(Math.abs(rect.y - 284) < 1e-6, `rect y = ${rect.y}, want 284`);
  assert.ok(Math.abs(rect.w - 44) < 1e-6, `rect w = ${rect.w}, want 44`);
  assert.ok(Math.abs(rect.h - 32) < 1e-6, `rect h = ${rect.h}, want 32`);
});

test("paintCanvasBundle strokes a line and fills a label at OrthoCamera2D screen coords (zoom 1, pan 0)", () => {
  const paint = loadCanvasPainter();
  const ctx = makeFakeContext2D();

  const bundle = {
    background: "#000",
    camera: { mode: "ortho2d", x: 0, y: 0, z: 1 },
    objects: [],
    lines: [
      {
        from: { x: 0, y: 0 },
        to: { x: 100, y: 0 },
        color: "#88ddff",
        lineWidth: 3,
      },
    ],
    labels: [
      {
        text: "hello",
        color: "#ffffff",
        font: "14px system-ui, sans-serif",
        position: { x: 0, y: 0 },
      },
    ],
  };

  paint(ctx, bundle, 800, 600, 1);

  // Line endpoints: (0,0) → screen (400, 300); (100,0) → screen (500, 300).
  const moves = callsOfType(ctx, "moveTo");
  const linesTo = callsOfType(ctx, "lineTo");
  const strokes = callsOfType(ctx, "stroke");
  assert.equal(moves.length, 1, "expected one moveTo");
  assert.equal(linesTo.length, 1, "expected one lineTo");
  assert.equal(strokes.length, 1, "expected one stroke");
  assert.ok(Math.abs(moves[0].x - 400) < 1e-6, `moveTo x = ${moves[0].x}, want 400`);
  assert.ok(Math.abs(moves[0].y - 300) < 1e-6, `moveTo y = ${moves[0].y}, want 300`);
  assert.ok(Math.abs(linesTo[0].x - 500) < 1e-6, `lineTo x = ${linesTo[0].x}, want 500`);
  assert.ok(Math.abs(linesTo[0].y - 300) < 1e-6, `lineTo y = ${linesTo[0].y}, want 300`);
  assert.equal(strokes[0].strokeStyle, "#88ddff", "line must use its color");
  assert.equal(strokes[0].lineWidth, 3, "line must use its lineWidth");

  // Label at world (0,0) → screen (400, 300).
  const texts = callsOfType(ctx, "fillText");
  assert.equal(texts.length, 1, "expected one fillText");
  assert.equal(texts[0].text, "hello");
  assert.equal(texts[0].fillStyle, "#ffffff", "label must use its color");
  assert.ok(Math.abs(texts[0].x - 400) < 1e-6, `label x = ${texts[0].x}, want 400`);
  assert.ok(Math.abs(texts[0].y - 300) < 1e-6, `label y = ${texts[0].y}, want 300`);
});

test("paintCanvasBundle applies zoom and pan from the OrthoCamera2D camera", () => {
  const paint = loadCanvasPainter();
  const ctx = makeFakeContext2D();

  // zoom=2, pan=(10,20). World point (10,20) must land at the viewport center.
  // World rect top-left corner (minX=10, maxY=20):
  //   screenX = (10 - 10) * 2 + 400 = 400
  //   screenY = 300 - (20 - 20) * 2 = 300
  // width = (maxX-minX)*zoom = (30-10)*2 = 40; height = (maxY-minY)*zoom = (20-0)*2 = 40
  const bundle = {
    background: "#101010",
    camera: { mode: "ortho2d", x: 10, y: 20, z: 2 },
    materials: [{ color: "#a0ff88" }],
    objects: [
      {
        kind: "rect",
        materialIndex: 0,
        bounds: { minX: 10, maxX: 30, minY: 0, maxY: 20 },
      },
    ],
    lines: [],
    labels: [],
  };

  paint(ctx, bundle, 800, 600, 1);

  const fills = nodeFillRects(ctx, 800, 600);
  assert.equal(fills.length, 1, "expected one node fillRect");
  const rect = fills[0];
  assert.ok(Math.abs(rect.x - 400) < 1e-6, `rect x = ${rect.x}, want 400`);
  assert.ok(Math.abs(rect.y - 300) < 1e-6, `rect y = ${rect.y}, want 300`);
  assert.ok(Math.abs(rect.w - 40) < 1e-6, `rect w = ${rect.w}, want 40 (20 world * 2 zoom)`);
  assert.ok(Math.abs(rect.h - 40) < 1e-6, `rect h = ${rect.h}, want 40 (20 world * 2 zoom)`);
});

test("paintCanvasBundle tolerates missing/empty arrays and absent background", () => {
  const paint = loadCanvasPainter();
  const ctx = makeFakeContext2D();

  // No objects/lines/labels keys at all, no background — must not throw and
  // must still clear the frame.
  assert.doesNotThrow(() => {
    paint(ctx, { camera: { mode: "ortho2d", x: 0, y: 0, z: 1 } }, 320, 240, 1);
  });
  assert.ok(callsOfType(ctx, "clearRect").length >= 1, "frame must still be cleared");
  assert.equal(callsOfType(ctx, "fillRect").length, 0, "no rects to fill");
  assert.equal(callsOfType(ctx, "stroke").length, 0, "no lines to stroke");
  assert.equal(callsOfType(ctx, "fillText").length, 0, "no labels to fill");
});

// -----------------------------------------------------------------------------
// Ortho-2D WebGPU camera math — sceneMat4Ortho2DView/Proj/ViewProj
// (bootstrap-src/11-scene-math.js, exported through window.__gosx_scene3d_api).
//
// sceneMat4Ortho2DViewProj is the JS half of the pinned cross-language golden
// contract with the native 2D board camera: render/bundle/math.go
// computeOrthoCamera2DMVP, guarded by TestComputeOrthoCamera2DMVP_Golden
// (render/bundle/ortho_camera_2d_golden_test.go). The values asserted below are
// copied verbatim from that Go test — if either side drifts, both suites fail.
//
// The helpers read the RAW engine.RenderCamera wire fields (mode, x/y = pan,
// z = zoom, near/far) and are deliberately NOT routed through sceneRenderCamera,
// whose 3D defaults (z→6, near→0.05, far→128) would silently mangle them.
// -----------------------------------------------------------------------------

// loadScene3DApiContext boots the full monolithic bundle in a fake DOM and
// returns window.__gosx_scene3d_api — the same object the chunked
// bootstrap-feature-scene3d-webgpu.js prefix destructures at load time.
async function loadScene3DApiContext() {
  const env = createContext({});
  runScript(bootstrapSource, env.context, "bootstrap.js");
  await flushAsyncWork();
  const api = env.context.__gosx_scene3d_api;
  assert.ok(api, "bootstrap must publish window.__gosx_scene3d_api");
  return api;
}

function assertMat4Approx(out, expectations, label) {
  for (const [index, want] of expectations) {
    const got = out[index];
    assert.ok(
      Math.abs(got - want) <= 1e-5,
      `${label} m[${index}] = ${got}, want ${want}`,
    );
  }
}

test("bootstrap Scene3D ortho-2D viewProj matches the native computeOrthoCamera2DMVP golden", async () => {
  const api = await loadScene3DApiContext();
  const viewProj = api.sceneMat4Ortho2DViewProj;
  assert.equal(
    typeof viewProj,
    "function",
    "sceneMat4Ortho2DViewProj must be exported on __gosx_scene3d_api",
  );

  const out = new Float32Array(16);

  // zoom=1, pan=0, 200x100 → ortho scale 2/200, 2/100; identity translation.
  viewProj({ mode: "ortho2d", x: 0, y: 0, z: 1, near: -1, far: 1 }, 200, 100, out);
  assertMat4Approx(out, [
    [0, 0.01],
    [5, 0.02],
    [10, -1],
    [15, 1],
    [12, 0],
    [13, 0],
    [14, 0],
  ], "golden case 1");

  // pan=(10,20) → MVP translation = proj-scaled (-panX, -panY).
  viewProj({ mode: "ortho2d", x: 10, y: 20, z: 1, near: -1, far: 1 }, 200, 100, out);
  assertMat4Approx(out, [
    [0, 0.01],
    [5, 0.02],
    [12, -0.1],
    [13, -0.4],
  ], "golden case 2");

  // zoom=2 → half-extents halve → ortho scale doubles.
  viewProj({ mode: "ortho2d", x: 0, y: 0, z: 2, near: -1, far: 1 }, 200, 100, out);
  assertMat4Approx(out, [
    [0, 0.02],
    [5, 0.04],
  ], "golden case 3");
});

test("bootstrap Scene3D ortho-2D helpers apply the native defaults (zoom<=0→1, near/far 0→-1/1)", async () => {
  const api = await loadScene3DApiContext();
  const viewProj = api.sceneMat4Ortho2DViewProj;
  const view = api.sceneMat4Ortho2DView;
  const proj = api.sceneMat4Ortho2DProj;
  assert.equal(typeof viewProj, "function", "sceneMat4Ortho2DViewProj must be exported");
  assert.equal(typeof view, "function", "sceneMat4Ortho2DView must be exported");
  assert.equal(typeof proj, "function", "sceneMat4Ortho2DProj must be exported");

  const out = new Float32Array(16);

  // zoom 0 (and missing near/far) → zoom 1, near -1, far 1: identical to
  // golden case 1 (mirrors the native guards in computeOrthoCamera2DMVP).
  viewProj({ mode: "ortho2d", x: 0, y: 0, z: 0, near: 0, far: 0 }, 200, 100, out);
  assertMat4Approx(out, [
    [0, 0.01],
    [5, 0.02],
    [10, -1],
    [14, 0],
    [15, 1],
  ], "defaults");

  // View is a pure translation by (-panX, -panY, 0) — zoom never leaks in.
  view({ mode: "ortho2d", x: 7, y: -3, z: 5, near: -1, far: 1 }, out);
  assertMat4Approx(out, [
    [0, 1],
    [5, 1],
    [10, 1],
    [12, -7],
    [13, 3],
    [14, 0],
    [15, 1],
  ], "view");

  // Proj emits the WebGL depth convention (NDC z in [-1,1]) to match the
  // native golden — the WebGPU [0,1] remap happens in uploadFrameUniforms.
  proj({ mode: "ortho2d", x: 10, y: 20, z: 1, near: -1, far: 1 }, 200, 100, out);
  assertMat4Approx(out, [
    [0, 0.01],
    [5, 0.02],
    [10, -1],
    [12, 0],
    [13, 0],
    [14, 0],
    [15, 1],
  ], "proj");
});

test("bootstrap 16a uploadFrameUniforms takes the ortho-2D branch before the 3D camera normalizer", () => {
  const source = fs.readFileSync(
    path.join(__dirname, "bootstrap-src", "16a-scene-webgpu.js"),
    "utf8",
  );
  const start = source.indexOf("function uploadFrameUniforms(");
  const end = source.indexOf("function uploadLights(");
  assert.notEqual(start, -1, "uploadFrameUniforms must exist in 16a");
  assert.notEqual(end, -1, "uploadLights anchor must exist in 16a");
  const body = source.slice(start, end);

  const orthoGate = body.indexOf('camera.mode === "ortho2d"');
  const normalizer = body.indexOf("sceneRenderCamera(camera)");
  const depthRemap = body.indexOf("scratchProjMatrix[2]");
  assert.notEqual(orthoGate, -1, "uploadFrameUniforms must gate on camera.mode === \"ortho2d\"");
  assert.notEqual(normalizer, -1, "the 3D path must still normalize through sceneRenderCamera");
  assert.ok(
    orthoGate < normalizer,
    "the ortho-2D branch must precede sceneRenderCamera — the normalizer strips mode and applies 3D defaults (z→6, near→0.05, far→128), silently mangling 2D cameras",
  );
  assert.match(body, /sceneMat4Ortho2DView\(camera,\s*scratchViewMatrix\)/);
  assert.match(body, /sceneMat4Ortho2DProj\(camera,\s*width,\s*height,\s*scratchProjMatrix\)/);
  // The ortho proj is emitted in WebGL convention (z in [-1,1], matching the
  // native golden) and must still flow through the WebGPU depth remap.
  assert.notEqual(depthRemap, -1, "WebGL→WebGPU depth remap must remain");
  assert.ok(depthRemap > orthoGate, "depth remap must stay downstream of the ortho-2D branch");

  // The sceneApi bridge: the chunked build's 26e prefix must import the
  // helpers, and 10-runtime-scene-core.js must export them.
  const prefix = fs.readFileSync(
    path.join(__dirname, "bootstrap-src", "26e-feature-scene3d-webgpu-prefix.js"),
    "utf8",
  );
  assert.match(prefix, /var sceneMat4Ortho2DView = sceneApi\.sceneMat4Ortho2DView;/);
  assert.match(prefix, /var sceneMat4Ortho2DProj = sceneApi\.sceneMat4Ortho2DProj;/);
  assert.match(prefix, /var sceneMat4Ortho2DViewProj = sceneApi\.sceneMat4Ortho2DViewProj;/);

  const core = fs.readFileSync(
    path.join(__dirname, "bootstrap-src", "10-runtime-scene-core.js"),
    "utf8",
  );
  assert.match(core, /sceneMat4Ortho2DView:/);
  assert.match(core, /sceneMat4Ortho2DProj:/);
  assert.match(core, /sceneMat4Ortho2DViewProj:/);
});

// -----------------------------------------------------------------------------
// Ortho-2D board bundle → 16a WebGPU renderer (adaptOrtho2DBoardBundle seam)
//
// The Go board pipeline (render/bundle2d.ComputeCanvasGPUBundle) marshals an
// engine.RenderBundle in the NATIVE renderer vocabulary: rect quads live in
// bundle.objects (vertexOffset/vertexCount/materialIndex) sliced into
// bundle.worldPositions/worldNormals/worldUVs. 16a draws from the JS
// scene-core vocabulary instead (meshObjects + worldMeshPositions/...). The
// adaptOrtho2DBoardBundle seam at the top of 16a's render() bridges the two by
// ZERO-COPY aliasing — these tests drive the REAL chunked renderer
// (bootstrap-feature-scene3d.js + bootstrap-feature-scene3d-webgpu.js) against
// a fake GPUDevice and assert observable draw behavior, not source shape.
//
// Fixtures are the SHARED Go↔JS goldens in render/bundle2d/testdata/ —
// bundle2d's TestBoardGPUBundleGolden asserts
// MarshalCanvasBundle(ComputeCanvasGPUBundleWithBackground(nodes, "#102030",
// 640, 480, 0.5, 0, 0)) equals these bytes byte-for-byte (the node lists live
// next to that test), so what renders here is EXACTLY what Go emits.
// Regenerate with GOSX_UPDATE_BOARD_FIXTURES=1 go test ./render/bundle2d/.
// Zoom 0.5 is deliberate: at zoom < 1 the board objects are NOT bounds-culled
// by sceneBoundsViewCulled, so the fixtures also pin the regression where
// scene-core's buildSceneWorldDrawPlan misread native board objects (which
// have worldPositions but no worldColors) as world-line records and threw.
// -----------------------------------------------------------------------------

function readBoardFixture(name) {
  return fs.readFileSync(
    path.join(__dirname, "..", "..", "render", "bundle2d", "testdata", name),
    "utf8",
  );
}

// Two-rect board ({ID:"card-a",Kind:"rect",X:16,Y:24,Width:200,Height:120,
// Color:"#3a86ff"}, {ID:"card-b",Kind:"rect",X:280,Y:60,Width:160,Height:90,
// Color:"#ffbe0b"}). NOTE: the first object's vertexOffset/materialIndex are
// ABSENT — Go's `omitempty` elides zero values on the wire; the seam restores
// both. Materials carry the Selena BoardFill attach (customVertexWGSL/
// customFragmentWGSL/shaderBackend/shaderLayout + customUniforms.baseColor).
const goBoardBundleRectsJSON = readBoardFixture("board_fixture_rects.json");

// Mixed board (1 rect + 2 lines + 1 label + 1 sprite). Since M1 slice 2A the
// Go attach (AttachBoardGPUGeometry) expands lines and sprites into z=0
// quads appended to objects/worldPositions in painter z-order (rect → lines
// → sprite), so the fixture carries FOUR drawable objects: the rect and the
// two lines on flat+Selena BoardFill materials, the sprite on a bare
// {kind:"sprite", color:"#ffffff", texture, unlit} material that draws
// unlit-textured through 16a's default PBR object path (no Selena attach). The
// lines/labels/sprites wire arrays still ride unchanged
// ({from:{x,y},to:{x,y},color,lineWidth} etc.); labels stay undrawn here
// (slice 2C renders them as a DOM overlay).
const goBoardBundleMixedJSON = readBoardFixture("board_fixture_mixed.json");
const goBoardBundleMixedWithHTMLJSON = JSON.stringify(Object.assign(
  {},
  JSON.parse(goBoardBundleMixedJSON),
  {
    html: [{
      id: "page:home",
      markup: '<h1 contenteditable data-studio-field="home.hero.headline">Hi</h1>',
      x: 20,
      y: 20,
      width: 240,
      height: 80,
      pointerEvents: "auto",
    }],
  },
));

// parseWGSLBindingKinds extracts every `@group(G) @binding(B) var ...`
// declaration from a WGSL source string into a Map keyed "G:B" -> kind, where
// kind is one of "uniform", "storage-read", "storage-read_write", "texture",
// or "sampler". This is a lightweight scan (mirroring the same small set of
// regexes the Go host-binding-descriptor test uses --
// examples/gosx-docs/.../water/selena_wgsl_binding_test.go -- not a full WGSL
// parser), used ONLY by makeFakeGPUDevice's opt-in `validateBindings` mode.
function parseWGSLBindingKinds(source) {
  const kinds = new Map();
  const src = typeof source === "string" ? source : "";
  const textureOrSamplerRE = /@group\(\s*(\d+)\s*\)\s*@binding\(\s*(\d+)\s*\)\s*var\s+\w+\s*:\s*(texture_\w+(?:<[^>]*>)?|sampler)\s*;/g;
  const storageRE = /@group\(\s*(\d+)\s*\)\s*@binding\(\s*(\d+)\s*\)\s*var<storage,\s*(read_write|read)>\s*\w+\s*:/g;
  const uniformRE = /@group\(\s*(\d+)\s*\)\s*@binding\(\s*(\d+)\s*\)\s*var<uniform>\s*\w+\s*:/g;
  let m;
  while ((m = textureOrSamplerRE.exec(src))) {
    kinds.set(m[1] + ":" + m[2], m[3] === "sampler" ? "sampler" : "texture");
  }
  while ((m = storageRE.exec(src))) {
    kinds.set(m[1] + ":" + m[2], m[3] === "read_write" ? "storage-read_write" : "storage-read");
  }
  while ((m = uniformRE.exec(src))) {
    kinds.set(m[1] + ":" + m[2], "uniform");
  }
  return kinds;
}

// gpuBindGroupLayoutEntryKind classifies one GPUBindGroupLayoutEntry the same
// way parseWGSLBindingKinds classifies a WGSL declaration, so the two can be
// compared directly by makeFakeGPUDevice's validator.
function gpuBindGroupLayoutEntryKind(entry) {
  if (!entry) return null;
  if (entry.texture) return "texture";
  if (entry.sampler) return "sampler";
  if (entry.buffer) {
    if (entry.buffer.type === "uniform") return "uniform";
    if (entry.buffer.type === "storage") return "storage-read_write";
    if (entry.buffer.type === "read-only-storage") return "storage-read";
  }
  return null;
}

// makeFakeGPUDevice builds a recording GPUDevice double that satisfies every
// device call 16a's synchronous init + render() issue on the board path:
